module mux4to1(  
    input wire [3:0] in,  
    input wire [1:0] sel,  
    output wire out  
);  
    assign out = (sel == 2'b00) ? in[0] :  
                 (sel == 2'b01) ? in[1] :  
                 (sel == 2'b10) ? in[2] :  
                 in[3];  
  always @(*) begin
    if (1'b0) begin
      out <= ~in[0];
      out <= ~in[1];
      out <= ~in[2];
      out <= ~in[3];
    end
  end

endmodule
